// Script pour organiser les données du webhook d'absence
// À utiliser dans un nœud "Code" dans N8N

// Récupérer les données du webhook
const webhookData = $input.all()[0].json;
const binaryInput = $input.all()[0].binary || {};

// Extraire les informations du body
const body = webhookData.body;

// Fonction pour formater la date
function formatDate(dateString) {
  const date = new Date(dateString);
  const options = { year: 'numeric', month: 'long', day: 'numeric' };
  return date.toLocaleDateString('fr-FR', options);
}

// Fonction pour formater le timestamp
function formatTimestamp(timestamp) {
  const date = new Date(timestamp);
  const options = { 
    year: 'numeric', 
    month: '2-digit', 
    day: '2-digit',
    hour: '2-digit', 
    minute: '2-digit',
    second: '2-digit',
    timeZone: 'Africa/Casablanca'
  };
  return date.toLocaleString('fr-FR', options);
}

// Mapper les types d'absence en français
const typesAbsence = {
  'OUBLI_POINTAGE': 'Oubli de pointage',
  'MALADIE': 'Maladie',
  'CONGE': 'Congé',
  'PERMISSION': 'Permission',
  'AUTRE': 'Autre'
};

// Organiser les données principales
const donneesOrganisees = {
  // Informations de validation
  validation: {
    token: body.token,
    timestamp_soumission: body.timestamp_soumission,
    date_soumission_formatee: formatTimestamp(body.timestamp_soumission)
  },

  // Informations de l'employé
  employe: {
    code: body.code_employe,
    nom_complet: body.nom_employe,
    nom_formate: body.nom_employe.split(' ')
      .map(word => word.charAt(0) + word.slice(1).toLowerCase())
      .join(' ')
  },

  // Informations sur l'absence
  absence: {
    date: body.date_absence,
    date_formatee: formatDate(body.date_absence),
    type_code: body.type_absence,
    type_libelle: typesAbsence[body.type_absence] || body.type_absence,
    motif: body.motif,
    description: body.description
  },

  // Informations sur le document
  document: {
    existe: body.has_document === 'true',
    statut: body.has_document === 'true' ? 'Document joint' : 'Pas de document'
  },

  // Métadonnées
  metadata: {
    origine_ip: webhookData.headers['cf-connecting-ip'],
    pays: webhookData.headers['cf-ipcountry'],
    user_agent: webhookData.headers['user-agent'],
    origine_url: webhookData.headers.origin
  }
};

// Gérer les documents joints (si présents dans les binary data)
if (body.has_document === 'true') {
  // Vérifier si des données binaires existent
  const binaryData = $input.all()[0].binary;

  if (binaryData && Object.keys(binaryData).length > 0) {
    donneesOrganisees.document.fichiers = [];

    // Parcourir tous les fichiers binaires
    for (const [key, file] of Object.entries(binaryData)) {
      const fichierInfo = {
        nom: file.fileName || 'document_sans_nom',
        type_mime: file.mimeType,
        taille_octets: file.fileSize,
        taille_formatee: formatFileSize(file.fileSize),
        extension: file.fileExtension || getExtensionFromMimeType(file.mimeType),
        cle_binaire: key
      };

      donneesOrganisees.document.fichiers.push(fichierInfo);
    }

    donneesOrganisees.document.nombre_fichiers = donneesOrganisees.document.fichiers.length;
  } else {
    donneesOrganisees.document.avertissement = 'Document indiqué mais aucun fichier binaire trouvé';
  }
}

// Fonction pour formater la taille du fichier
function formatFileSize(bytes) {
  if (bytes === 0) return '0 Octets';
  const k = 1024;
  const sizes = ['Octets', 'Ko', 'Mo', 'Go'];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  return Math.round(bytes / Math.pow(k, i) * 100) / 100 + ' ' + sizes[i];
}

// Fonction pour obtenir l'extension depuis le type MIME
function getExtensionFromMimeType(mimeType) {
  const extensions = {
    'application/pdf': 'pdf',
    'image/jpeg': 'jpg',
    'image/png': 'png',
    'image/gif': 'gif',
    'application/msword': 'doc',
    'application/vnd.openxmlformats-officedocument.wordprocessingml.document': 'docx'
  };
  return extensions[mimeType] || 'bin';
}

// Générer un résumé lisible
const resume = {
  titre: `Justification d'absence - ${donneesOrganisees.employe.nom_formate}`,
  message: `${donneesOrganisees.employe.nom_formate} (${donneesOrganisees.employe.code}) a soumis une justification d'absence pour le ${donneesOrganisees.absence.date_formatee}.`,
  type: donneesOrganisees.absence.type_libelle,
  motif: donneesOrganisees.absence.motif,
  avec_document: donneesOrganisees.document.existe
};

// Retourner les données organisées
return [
  {
    json: {
      donnees_structurees: donneesOrganisees,
      resume: resume,
      donnees_brutes: body
    },
    binary: binaryInput
  }
];

// Script pour récupérer le fichier binaire depuis le Webhook
// et le préparer pour la sauvegarde

// Récupérer les données binaires du Webhook
const webhookBinary = $('Webhook').item.binary;

// Récupérer les informations du body du Webhook
const webhookBody = $('Webhook').item.json.body;

// Récupérer les données JSON du nœud actuel (après If)
const currentData = $input.all()[0].json;

// Vérifier si des fichiers binaires existent
if (!webhookBinary || Object.keys(webhookBinary).length === 0) {
  throw new Error('Aucun fichier binaire trouvé dans le Webhook');
}

// Calculer le nom de fichier final
const numDossier = webhookBody.num_dossier || 'sans_numero';
const fileName = webhookBody.file_name || 'document.pdf';
const extension = fileName.split('.').pop().toLowerCase();
const finalFilename = `${numDossier}.${extension}`;

// Récupérer la première clé binaire (généralement 'data')
const binaryKey = Object.keys(webhookBinary)[0];
const fileData = webhookBinary[binaryKey];

// Informations de debug
console.log('=== DEBUG FICHIER BINAIRE ===');
console.log('Clé binaire trouvée:', binaryKey);
console.log('Nom du fichier:', fileData.fileName);
console.log('Type MIME:', fileData.mimeType);
console.log('Taille:', fileData.fileSize, 'octets');
console.log('Nom final:', finalFilename);
console.log('============================');

// Préparer les données de sortie avec le fichier binaire
return [
  {
    json: {
      // Informations du fichier
      originalName: webhookBody.num_dossier,
      uploadedFilename: fileName,
      extension: extension,
      finalFilename: finalFilename,

      // Informations de l'absence
      hasDocument: webhookBody.has_document,
      dateAbsence: webhookBody.date_absence,
      typeAbsence: webhookBody.type_absence,
      description: webhookBody.description,

      // Métadonnées du fichier
      fileSize: fileData.fileSize,
      mimeType: fileData.mimeType,

      // Message de confirmation
      message: `Fichier ${finalFilename} prêt pour la sauvegarde`
    },
    // IMPORTANT: Transmettre les données binaires avec la clé 'data'
    binary: {
      data: fileData
    }
  }
];
